mapper.select:

WHERE e.del_flag = '0' AND e.tenant_id = #{tenantId}

    AND e.equipment_code LIKE CONCAT('%', #{equipmentCode}, '%')


    AND e.equipment_name LIKE CONCAT('%', #{equipmentName}, '%')


    AND e.equipment_type = #{equipmentType}


    AND e.status = #{status}


    AND e.create_time >= #{params.beginTime}


    AND e.create_time <= #{params.endTime}

ORDER BY e.equipment_id DESC

